import { useEffect, useState } from "react"
import { getAll } from "../api/robotApi"
import { useDispatch, useSelector } from "react-redux"
import { set_arr_robots } from "../redux/dataReducerRobot";
import { add } from "../redux/dateReducerCart";
import './shop.css';

function Shop() {
    const dis = useDispatch();

    const arr = useSelector(s => s.robot?.arr_robots || [])  
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);

    useEffect(() => {
        let mounted = true; // fallback if getAll doesn't support AbortController
        async function getData() {
            if (arr.length === 0) {
                setLoading(true);
                setError(null);
                try {
                    const arr_robots = await getAll();
                    if (!mounted) return;
                    dis(set_arr_robots(arr_robots));
                } catch (err) {
                    if (!mounted) return;
                    console.error("Failed to fetch robots:", err);
                    setError("שגיאה בטעינת הנתונים");
                } finally {
                    if (mounted) setLoading(false);
                }
            }
        }
        getData();
        return () => { mounted = false; }
    }, [arr.length, dis])

    const apiBase = (process.env.REACT_APP_API_URL || 'http://localhost:8080').replace(/\/$/, '');

    return (
        <div className="shop-page-container">
            <h1 className="shop-title">גלריית הרובוטים</h1>

            {loading && <div className="loading">טוען...</div>}
            {error && <div className="error">{error}</div>}

            <div className="products-grid">
                {
                    arr.map(s =>
                        <div key={s._id} className="robot-card">
                            
                            <div className="image-container">
                                <img src={`${apiBase}/${s.img}`} alt={s.robotName || 'robot'} />
                            </div>

                            <div className="card-content">
                                <h2 className="robot-name">{s.robotName}</h2>
                                <h3 className="robot-price">{s.price} ₪</h3>
                                <h3 className="stock-info">במלאי: {s.amountInStock} יחידות</h3>
                                
                                <div className="card-actions">
                                    <button className="btn-details">פרטים נוספים</button>
                                    <button className="btn-add-cart" onClick={() => {
                                        dis(add(s))
                                    }}>הוסף לסל</button>
                                </div>
                            </div>
                        </div>
                    )
                }
            </div>
        </div>
    )
}

export default Shop;
